vulnerabilities.fix:
`args` 배열의 각 요소를 `join('-')`하기 전에 `utils.escapeRegex` 함수를 사용하여 모든 정규식 메타 문자를 이스케이프해야 합니다. 이렇게 하면 사용자 입력이 정규식 문자로 해석되는 것을 방지하고 리터럴 문자열로 처리하게 됩니다.

```javascript
const expandRange = (args, options) => {
  if (typeof options.expandRange === 'function') {
    return options.expandRange(...args, options);
  }

  args.sort();
  // 수정: 각 요소를 join하기 전에 이스케이프합니다.
  const escapedArgs = args.map(v => utils.escapeRegex(v));
  const value = `[${escapedArgs.join('-')}]`; // 이스케이프된 args 사용

  try {
    new RegExp(value);
  } catch (ex) {
    // 이 폴백 경로는 이미 이스케이프 처리를 하고 있으므로 안전합니다.
    return args.map(v => utils.escapeRegex(v)).join('..');
  }

  return value;
};
```
